var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"한소림. 호출을 받고 사장실에 방문했다.","JPN":"ハネダ・ミズキ。呼び出しを受け、ただいま社長室に到着。","ENG":" Han Sorim, reporting to your summons.","TWN":"韓蕭林，收到呼叫造訪老闆辦公室。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"......그래서, 종신계약 말이군. 전쟁에 굶주린 본관을 선발하다니, 탁월한 안목이다.","JPN":"……それで、終身契約の件か。戦争に飢えている本官を選ぶとは、お目が高い。","ENG":" Okay, a lifetime contract. You've got a good eye for soldiers, picking me.","TWN":"……所以，這是終身契約。你居然選擇了渴望戰爭的本官，真是明智之舉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"하지만 한 가지 간과한 사실이 있다. 바로 본관이 위기에 처한 전우들을 돕고 사라지는 고독한 늑대라는 것......","JPN":"しかし、一つだけ見逃している事がある。それは本官が危機にさらされた戦友たちを救い、姿を消してしまう孤独なオオカミであること……","ENG":" But you've overlooked something. I'm a lone wolf who disappears after helping out her comrades...","TWN":"但是你忽略了一個事實。本官是拯救完面臨危機的戰友後，就會消失的一匹孤狼……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":" ......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"겨, 격납고 출입증? 함선 건조 실습에도 참여할 수 있어? 정말?","JPN":"か、格納庫の出入許可証？艦船建造の実習にも参加できるんですか？本当に？","ENG":" H-hangar pass? I can help construct ships? For real?","TWN":"機……機庫通行證？可以參加艦船建造的實習？真的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"바, 방금 발언은 묵과할 수 없다...!","JPN":"い、今の発言は黙過できん……！","ENG":" I-I'll have to reconsider your offer based on that comment. ","TWN":"剛、剛才的發言我可不能裝作沒聽到……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"스미스 병장은 전투 교양은 충분해도 기술적인 소양이 부족하니까. ......본관은 괜찮지만.","JPN":"スミス兵長は、戦闘に関しては十分な教養を身につけているが、技術に関する教養は不足している。……本官は大丈夫だ。","ENG":" Because Sergeant Smith could use some education in technology. ... Not me, though.","TWN":"雖然史密斯兵長具有戰鬥教養，但技術素養卻不足……本官是無所謂啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"그, 그렇지? 스미스 병장?","JPN":"そ、そうだな？スミス兵長？","ENG":" I-isn't that right, Sergeant Smith?","TWN":"對、對吧？史密斯兵長？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"음음. 스미스 병장도 무척 기대하는 눈치로군. ......본관은 정말 괜찮지만.","JPN":"うむ、スミス兵長もとても期待してるようだ。……本官は遠慮しても構わないが。","ENG":" Mm, mm. Sergeant Smith seems to be very excited for this opportunity. ... Not me, though.","TWN":"嗯嗯。史密斯兵長也很期待呢……本官是真的無所謂啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SORIM_XMAS_NULL_NULL","text":{"KOREA":"그, 그럼 사장님. 계약서...... 주세요.","JPN":"そ、それでは、社長。契約書を……ください。","ENG":" Th-then, Boss... Give me the Contract. Please?","TWN":"那、那麼老闆。請給我……契約書。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};